from cryptography.fernet import Fernet
import os

# Generate a key and add it to the environment variables
key = Fernet.generate_key()
os.environ["ENCRYPT_KEY"] = key.decode('utf-8')

def encrypt_credit_card(card_number):
    cipher_suite = Fernet(os.environ.get('ENCRYPT_KEY').encode('utf-8'))
    cipher_text = cipher_suite.encrypt(card_number.encode('utf-8'))
    return cipher_text

def decrypt_credit_card(cipher_text):
    cipher_suite = Fernet(os.environ.get('ENCRYPT_KEY').encode('utf-8'))
    card_number = cipher_suite.decrypt(cipher_text)
    return card_number.decode('utf-8')